import{_ as e,o as a,c as i,ae as r}from"./chunks/framework.D9JM1nqk.js";const m=JSON.parse('{"title":"🏷️ ระบบเว็บไซต์ขายแผ่นและตลับเกม","description":"","frontmatter":{},"headers":[],"relativePath":"dev-home.md","filePath":"dev-home.md"}'),l={name:"dev-home.md"};function d(o,t,n,s,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="🏷️-ระบบเว็บไซต์ขายแผ่นและตลับเกม" tabindex="-1">🏷️ ระบบเว็บไซต์ขายแผ่นและตลับเกม <a class="header-anchor" href="#🏷️-ระบบเว็บไซต์ขายแผ่นและตลับเกม" aria-label="Permalink to &quot;🏷️ ระบบเว็บไซต์ขายแผ่นและตลับเกม&quot;">​</a></h1><p>เราเป็นระบบร้านค้าสำหรับการขายแผ่นเกม (Game Disc and Cartridge E-Commerce System) ที่เราได้รวบรวมจากแหล่งต่าง ๆ ทั่วทุกมุมโลก และทุกแนวเกมที่เป็นไปได้ไม่ว่าจะเป็นเกมเล่นในครอบครัว, เกมผ่านด่าน, เกมเนื้อเรื่อง, เกมยิงปืน, หรือเกมอะไรก็ตามจากทุกยุค-ทุกสมัย ทั้งหมดนี้ถูกสร้างขึ้นด้วยใจรักจากกลุ่มนักศึกษาทั้ง 5 คน:</p><ul><li>67168514 ปิยะบุตร อิ่มทอง - <a href="https://github.com/iKla47" target="_blank" rel="noreferrer">iKla47</a> (Backend Developer &amp; Database Administrator)</li><li>67163266 สิรภพ อ่วมแก้ว - <a href="https://github.com/SiRaCCC" target="_blank" rel="noreferrer">SiRaCCC</a> (Backend Developer)</li><li>67117502 ชนันธร สะอาดจินดา - <a href="https://github.com/chananthornsaa" target="_blank" rel="noreferrer">chananthornsaa</a> (Project Manager / System Analyst)</li><li>67151039 ณัฐดนัย แสงศรี - <a href="https://github.com/Bek0saMa" target="_blank" rel="noreferrer">Beky0mi</a> (Frontend Developer/UI Designer)</li><li>67173119 สุวิจักขณ์ ทัพเจริญ - <a href="https://github.com/TimeSuwichak" target="_blank" rel="noreferrer">straycatalwaysstay</a> (Frontend Dev/UI Designer)</li></ul><h2 id="หลักการและเหตุผล-relationable" tabindex="-1">หลักการและเหตุผล (Relationable) <a class="header-anchor" href="#หลักการและเหตุผล-relationable" aria-label="Permalink to &quot;หลักการและเหตุผล (Relationable)&quot;">​</a></h2><p>ในปัจจุบันสะดวกความสามารถในการสืบค้นได้ร้องขอการสัง่ซื้อผ่านทางดิจิทัล (Digital Download) เช่นการซื้อเกมผ่านทางแพลตฟอร์มดิจิทัลทำให้ผู้คนจำนวนมากสนใจในการเล่นเกมสด (Retro Games) ที่ใช้อยู่บนคอนโซล (Console) บ้านเก่าแบบเหล่านั้นเพราะว่าเรามีนวัตกรรมใหม่ในการซื้อหาของรสนิยมคลาสสิก ส่วนมากของผู้คนที่สนใจอยู่ในเขตต่างๆ (Zone) และการบริหารจัดการบนแพลตฟอร์ม</p><p>บางครั้ง การสั่งซื้อสินค้าออนไลน์บนเว็บไซต์ที่จำหน่ายเกม สามารถที่จะดำเนินการได้ อย่างไรก็ตาม ผลมาจากการว่างของการบริหารจัดการ E-Commerce ที่มีความเชี่ยวชาญเฉพาะสำหรับการขายผ่านอินเทอร์เน็ต ผลมาจากความต้องการในการปรับปรุงระบบเพื่อเพิ่มประสิทธิภาพและการตอบสนองของผู้ใช้</p><h2 id="วัตถุประสงค์ของโครงงาน-objectives" tabindex="-1">วัตถุประสงค์ของโครงงาน (Objectives) <a class="header-anchor" href="#วัตถุประสงค์ของโครงงาน-objectives" aria-label="Permalink to &quot;วัตถุประสงค์ของโครงงาน (Objectives)&quot;">​</a></h2><ol><li>เพื่อพัฒนาระบบพาณิชย์อิเล็กทรอนิกส์ (E-Commerce) สำหรับร้านขายแผ่นและตลับเกม ทั้งรูปแบบเก่าและใหม่</li><li>เพื่อสร้างระบบการจัดการข้อมูลสินค้า (Product Management)<br> ที่สามารถแบ่งหมวดหมู่และรายละเอียดเฉพาะของแผ่นและตลับเกมได้อย่างเป็นระบบ</li><li>เพื่อพัฒนาระบบจัดการคำสั่งซื้อ (Order Management) และจำลองการติดตามสถานะการจัดส่งพัสดุ (Mock Shipping API) ที่ช่วยให้กระบวนการซื้อขายครบวงจร</li><li>เพื่อสร้างระบบรายงานยอดขาย (Revenue Dashboard) สำหรับผู้บริหาร เพื่อนำข้อมูลไปใช้ในการวิเคราะห์และวางแผนการตลาด</li><li>เพื่อศึกษาและประยุกต์ใช้ความรู้ด้านการพัฒนาระบบซอฟต์แวร์ตามวงจรการพัฒนาระบบ (SDLC) ในสถานการณ์จำลองจริง</li></ol><h2 id="ขอบเขตของระบบ-system-scope" tabindex="-1">ขอบเขตของระบบ (System Scope) <a class="header-anchor" href="#ขอบเขตของระบบ-system-scope" aria-label="Permalink to &quot;ขอบเขตของระบบ (System Scope)&quot;">​</a></h2><p>ระบบได้รับการออกแบบเพื่อรองรับกลุ่มผู้ใช้งาน (Actors) 3 กลุ่มหลัก ดังนี้:</p><ul><li><code>ลูกค้า (Customer)</code>: ในฐานะผู้ซื้อ จะสามารถเข้าถึงระบบสมาชิก (Register / Login) เพื่อใช้งานระบบค้นหาสินค้า ระบบคัดกรองสินค้าแบบละเอียด ระบบรายการสินค้าที่ชอบ ตะกร้าสินค้า และการชำระเงินออนไลน์ รวมไปถึงการติดตามสถานการณ์จัดส่งพัสดุได้อย่างสะดวก</li><li><code>พนักงาน (Staff)</code>: ในฐานะผู้ดูแลการจัดส่งสต็อกและออเดอร์ จะมีเครื่องมือสำหรับจัดการข้อมูลสินค้า การระบุเกรดและสภาพสินค้า รวมถึงระบบจัดการสต็อกและสถานะคำสั่งซื้อ เพื่อความถูกต้องแม่นยำและลดข้อผิดพลาดในการทำงาน</li><li><code>ผู้จัดการ (Manager)</code>: ในฐานะผู้ดูแลระบบ (Admin) จะสามารถเข้าถึงระบบรายงานยอดขาย (Revenue Dashboard) ซึ่งจะแสดงผลแบบภาพรวมเพื่อใช้ประกอบการวิเคราะห์ วางแผนการตลาด และการตัดสินใจทางธุรกิจ</li></ul><p>ความสามารถหลักของระบบ (Main Functions)</p><ul><li><ol><li>ระบบสมาชิก (Register / Login) สำหรับลูกค้า</li></ol></li><li><ol start="2"><li>ระบบจัดการข้อมูลสินค้า ระบุเกรดและสภาพสินค้า</li></ol></li><li><ol start="3"><li>ระบบค้นหาสินค้า ตะกร้าสินค้า ระบบคัดกรองสินค้าแบบละเอียด ระบบรายการสินค้าที่ชอบ และการชำระเงินออนไลน์</li></ol></li><li><ol start="4"><li>ระบบจัดการคำสั่งซื้อและจำลองการอัปเดตสถานะการจัดส่งพัสดุ (Mock Shipping API)</li></ol></li><li><ol start="5"><li>ระบบรายงานยอดขาย (Revenue Dashboard)</li></ol></li></ul><h2 id="แนวทางการพัฒนาตาม-sdlc-system-development-life-cycle" tabindex="-1">แนวทางการพัฒนาตาม SDLC (System Development Life Cycle) <a class="header-anchor" href="#แนวทางการพัฒนาตาม-sdlc-system-development-life-cycle" aria-label="Permalink to &quot;แนวทางการพัฒนาตาม SDLC (System Development Life Cycle)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ขั้นตอน (Phase)</th><th>รายละเอียดโดยย่อ (Brief Description)</th></tr></thead><tbody><tr><td>1. Planning</td><td>วิเคราะห์ความต้องการและกำหนดขอบเขตของระบบ</td></tr><tr><td>2. Analysis</td><td>วิเคราะห์กระบวนการทำงานและจำลองระบบ (Use Case, ER-Diagram)</td></tr><tr><td>3. Design</td><td>ออกแบบสถาปัตยกรรมระบบ ฐานข้อมูล และหน้าจอผู้ใช้งาน (UI/UX)</td></tr><tr><td>4. Development</td><td>พัฒนา Frontend ด้วย React และ HTML/CSS พร้อมพัฒนา Backend API ด้วย Node.js โดยควบคุมเวอร์ชั่นโค้ดผ่าน GitHub</td></tr><tr><td>5. Testing</td><td>ทดสอบการทำงานแบบ Manual Testing, ตรวจสอบ API ด้วย Postman และทำการทดสอบการยอมรับของผู้ใช้</td></tr><tr><td>6. Deployment</td><td>นำระบบขึ้นเผยแพร่ (Deploy) ให้ใช้งานได้จริง</td></tr><tr><td>7. Maintenance</td><td>บำรุงรักษาและปรับปรุงระบบตามข้อเสนอแนะ</td></tr></tbody></table><h2 id="🛠️-เครื่องมือและเทคโนโลยี-tools-technologies" tabindex="-1">🛠️ เครื่องมือและเทคโนโลยี (Tools &amp; Technologies) <a class="header-anchor" href="#🛠️-เครื่องมือและเทคโนโลยี-tools-technologies" aria-label="Permalink to &quot;🛠️ เครื่องมือและเทคโนโลยี (Tools &amp; Technologies)&quot;">​</a></h2><p><em>(รายการนี้สถานะไม่คงที่ และอาจเปลี่ยนแปลงได้ในอนาคต)</em></p><ul><li><p>ส่วนหน้า (Frontend)</p><ul><li>NodeJS: รันไทม์สำหรับภาษาโปรแกรม JavaScript (ใช้ระหว่างพัฒนา)</li><li>TypeScript: ภาษาเพิ่มเติมจาก JavaScript ที่ช่วยจับข้อผิดพลาดผ่าน Type-Checking และ Interface</li><li>Vite: เครื่องมือในการสร้างเว็บไซต์และรันเซิร์ฟเวอร์ในระหว่างการพัฒนา (Development Server)</li><li>React: ไลบรารีอำนวยความสะดวกในการสร้าง UI ผ่านแนวคิดส่วนประกอบ (Component)</li><li>Styled Components: อำนวยความสะดวกในการใช้งาน CSS ร่วมกับ React</li><li>ESLint: ตรวจจับความผิดพลาดเชิงตรรกะในโค็ด</li></ul></li><li><p>ส่วนหลัง (Backend)</p><ul><li>Node.js: รันไทม์สำหรับภาษาโปรแกรม JavaScript</li><li>TypeScript: ภาษาเพิ่มเติมจาก JavaScript ที่ช่วยจับข้อผิดพลาดผ่าน Type-Checking และ Interface</li><li>Express: ระบบจัดการเชื่อมต่อระหว่างผู้ใช้บน HTTP/HTTPS</li><li>Express RateLimit: เพิ่มการจำกัดเข้าถึงทรัพยากรบนเซิร์ฟเวอร์ด้วยช่วงเวลา</li><li>Cors: เพิ่มการจำกัดเข้าถึงทรัพยากรบนเซิร์ฟเวอร์กับผู้ใช้บางส่วน</li><li>Compression: เพิ่มการบีบอัดข้อมูลระหว่างการเชื่อมต่อกับเซิร์ฟเวอร์</li><li>ESLint: ตรวจจับความผิดพลาดเชิงตรรกะในโค็ด</li><li>Nodemon: อำนวยความสำดวกในการพัฒนาระบบ</li></ul></li><li><p>ส่วนข้อมูล (Database)</p><ul><li>MySQL: สำหรับการจัดเก็บข้อมูลผู้ใช้, ข้อมูลสินค้า, ข้อมูลชำระเงิน, ข้อมูลจัดส่ง, ประวัติ, และรวมไปถึงกิจกรรมระบบ</li></ul></li><li><p>ส่วนออกแบบ (Design Tool)</p><ul><li>Draw.io: ใช้งานสำหรับการเขียนวาดภาพไดอะแกรม Use Cases Diagram, Sequences Diagram</li></ul></li></ul><h2 id="แนวทางการทดสอบ-testing-approach" tabindex="-1">แนวทางการทดสอบ (Testing Approach) <a class="header-anchor" href="#แนวทางการทดสอบ-testing-approach" aria-label="Permalink to &quot;แนวทางการทดสอบ (Testing Approach)&quot;">​</a></h2><p>ประเภทการทดสอบ (Testing Types)</p><ul><li>Functional Testing</li><li>User Acceptance Testing (UAT)</li></ul><p>เครื่องมือที่ใช้ (Tools)</p><ul><li>Postman</li><li>Manual Testing (ทดสอบการทำงานของระบบด้วยตนเองตามฟังก์ชันที่พัฒนา</li></ul><h2 id="ผลลัพธ์ที่คาดว่าจะได้รับ-expected-outcomes" tabindex="-1">ผลลัพธ์ที่คาดว่าจะได้รับ (Expected Outcomes) <a class="header-anchor" href="#ผลลัพธ์ที่คาดว่าจะได้รับ-expected-outcomes" aria-label="Permalink to &quot;ผลลัพธ์ที่คาดว่าจะได้รับ (Expected Outcomes)&quot;">​</a></h2><ol><li>ได้ระบบร้านขายแผ่นและตลับเกม (E-Commerce) ที่สามารถใช้งานได้จริงผ่านเว็บเบราว์เซอร์</li><li>ลูกค้าสามารถค้นหาสินค้า สั่งซื้อ และติดตามสถานการณ์จัดส่งได้อย่างสะดวกและรวดเร็ว</li><li>พนักงานมีเครื่องมือที่ช่วยในการจัดการสต็อกสินค้าและสถานะคำสั่งซื้อได้อย่างถูกต้องแม่นยำ ลดข้อผิดพลาดในการทำงานผู้จัดการมีระบบสรุปข้อมูลยอดขาย (Dashboard) ที่แสดงผลแบบภาพรวม ช่วยในการตัดสินใจทางธุรกิจ</li><li>ผู้จัดทำโครงงานได้รับทักษะและประสบการณ์ตรงในการพัฒนาระบบแบบ Full-stack และเข้าใจกระบวนการทำงานแบบวิศวกรรมซอฟต์แวร์</li></ol><h2 id="แผนการดําเนินงาน-4-สัปดาห์-work-plan-4-weeks" tabindex="-1">แผนการดำเนินงาน 4 สัปดาห์ (Work Plan: 4 Weeks) <a class="header-anchor" href="#แผนการดําเนินงาน-4-สัปดาห์-work-plan-4-weeks" aria-label="Permalink to &quot;แผนการดำเนินงาน 4 สัปดาห์ (Work Plan: 4 Weeks)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>สัปดาห์ (Week)</th><th>กิจกรรม (Activities)</th><th>รายละเอียดโดยย่อ (Brief Description)</th></tr></thead><tbody><tr><td>1.</td><td>วิเคราะห์และออกแบบระบบ (Analysis &amp; Design)</td><td>วิเคราะห์ความต้องการของระบบ ออกแบบ Use Case, ER-Diagram และ UI/UX</td></tr><tr><td>2.</td><td>พัฒนา Frontend (Frontend Development)</td><td>พัฒนาหน้าจอผู้ใช้ส่วนหน้าโดยใช้ React</td></tr><tr><td>3.</td><td>พัฒนา Backend และฐานข้อมูล (Backend &amp; Database Development)</td><td>สร้าง API จัดการสินค้า, เชื่อมต่อ API สำหรับชำระเงิน และทำ Mock Shipping</td></tr><tr><td>4.</td><td>ทดสอบระบบและนำเสนอผลงาน (Testing &amp; Presentation)</td><td>ทำ Manual Testing/UAT ตรวจสอบบัค และเตรียมพรีเซนต์โปรเจกต์</td></tr></tbody></table><h2 id="หลักการออกแบบสถาปัตยกรรมซอฟต์แวร์-software-architectural-design-principles" tabindex="-1">หลักการออกแบบสถาปัตยกรรมซอฟต์แวร์ (Software Architectural Design Principles) <a class="header-anchor" href="#หลักการออกแบบสถาปัตยกรรมซอฟต์แวร์-software-architectural-design-principles" aria-label="Permalink to &quot;หลักการออกแบบสถาปัตยกรรมซอฟต์แวร์ (Software Architectural Design Principles)&quot;">​</a></h2><p>เนื่องจากระบบต้องรองรับการทำงานของ E-Commerce ที่มีความซับซ้อน จึงได้กำหนดหลักการออกแบบดังนี้:</p><ul><li><code>Client-Server Architecture</code>: แยกการทำงานระหว่างส่วนแสดงผล (Frontend) และส่วนประมวลผล (Backend) ออกจากกันอย่างชัดเจน เพื่อให้ระบบสามารถบำรุงรักษาและขยายสเกล (Scalability) ได้ง่ายในอนาคต</li><li><code>RESTful API Integration</code>: การสื่อสารข้อมูลระหว่าง Frontend และ Backend จะใช้มาตรฐาน API เป็นตัวกลางในการส่งผ่านข้อมูล</li><li><code>Relational Data Structure</code>: ออกแบบโครงสร้างข้อมูลที่เน้นความสัมพันธ์ของเอนทิตี (Entity) ผ่านการจำลองระบบด้วย ER-Diagram เพื่อให้การจัดเก็บข้อมูลสินค้า หมวดหมู่ แพลตฟอร์ม และคำสั่งซื้อมีความเป็นระบบและลดความซ้ำซ้อน</li></ul><h2 id="การออกแบบสถาปัตยกรรมระบบ-system-architecture-design" tabindex="-1">การออกแบบสถาปัตยกรรมระบบ (System Architecture Design) <a class="header-anchor" href="#การออกแบบสถาปัตยกรรมระบบ-system-architecture-design" aria-label="Permalink to &quot;การออกแบบสถาปัตยกรรมระบบ (System Architecture Design)&quot;">​</a></h2><p>ระบบถูกแบ่งออกเป็น 4 ส่วนหลัก เพื่อให้การประมวลผลสอดคล้องกับแนวทางการพัฒนาซอฟต์แวร์ ดังนี้:</p><ul><li>Frontend Architecture (ส่วนติดต่อผู้ใช้งาน) <ul><li><strong>หน้าที่</strong>: ทำหน้าที่แสดงผลหน้าจอผู้ใช้งาน (UI/UX) และรับคำสั่งจากผู้ใช้งานทั้ง 3 กลุ่มผ่านเว็บเบราว์เซอร์</li><li><strong>เทคโนโลยีที่ใช้</strong>: พัฒนาด้วย React ร่วมกับ HTML/CSS</li></ul></li><li>Backend Architecture (ส่วนประมวลผลหลัก) <ul><li><strong>หน้าที่</strong>: ควบคุมตรรกะทางธุรกิจ (Business Logic) เช่น การคำนวณเงินในตะกร้าสินค้า การตรวจสอบสิทธิ์การเข้าใช้งาน (Authentication) และการจัดการคำสั่งซื้อ พร้อมทั้งควบคุมเวอร์ชันของโค้ดผ่าน GitHub</li><li><strong>เทคโนโลยีที่ใช้</strong>: พัฒนา Backend API ด้วย Node.js</li></ul></li><li>Database Architecture (ระบบจัดเก็บข้อมูล) <ul><li><strong>หน้าที่</strong>: จัดเก็บข้อมูลทุกอย่างในระบบ เช่น ข้อมูลผู้ใช้ สินค้า สต็อก และออเดอร์</li><li><strong>เทคโนโลยีที่ใช้</strong>: เชื่อมต่อฐานข้อมูล MySQL</li></ul></li><li>External Services (บริการภายนอก) <ul><li><strong>หน้าที่</strong>: บริการภายนอกที่นำมาเชื่อมต่อเพื่อเติมเต็มฟังก์ชันของ E-Commerce ให้กระบวนการซื้อขายครบวงจร</li><li><strong>เทคโนโลยีที่ใช้</strong>: Mock Shipping API สำหรับจำลองการอัปเดตและติดตามสถานะการจัดส่งพัสดุ</li></ul></li></ul><table tabindex="0"><thead><tr><th>ID</th><th>ระบบ/ฟีเจอร์ (Feature)</th><th>ผู้ใช้งาน (Actor)</th><th>คำอธิบาย (Description)</th></tr></thead><tbody><tr><td>FR-AUTH-01</td><td>สมัครสมาชิก (Register)</td><td>ลูกค้า</td><td>ผู้ใช้งานสามารถกรอกข้อมูลส่วนตัวเพื่อสร้างบัญชีใหม่ในระบบได้</td></tr><tr><td>FR-AUTH-02</td><td>เข้าสู่ระบบ (Login)</td><td>ลูกค้า, พนักงาน, ผู้จัดการ</td><td>ผู้ใช้งานเข้าสู่ระบบด้วย Username/Password ระบบจะตรวจสอบสิทธิ์และพาไปยังหน้าจอที่กำหนดตามบทบาท (Role-based access)</td></tr><tr><td>FR-PROD-01</td><td>จัดการข้อมูลสินค้า</td><td>พนักงาน</td><td>พนักงานสามารถ เพิ่ม/ลบ/แก้ไข ข้อมูลเกมได้ โดยระบุรายละเอียดเฉพาะ เช่น แพลตฟอร์ม, โซน, เกรด/สภาพสินค้า (มือ 1/มือ 2) และอัปเดตจำนวนสต็อก</td></tr><tr><td>FR-PROD-02</td><td>ค้นหาและกรองสินค้า</td><td>ลูกค้า</td><td>ลูกค้าสามารถค้นหาชื่อเกม และใช้ตัวกรองแบบละเอียด (Advanced Filter) เช่น กรองตามหมวดหมู่ แพลตฟอร์ม หรือช่วงราคา</td></tr><tr><td>FR-CART-01</td><td>จัดการตะกร้าสินค้า</td><td>ลูกค้า</td><td>ลูกค้าสามารถเพิ่ม แผ่น/ตลับเกม ลงในตะกร้า แก้ไขจำนวน หรือลบสินค้าออก และระบบจะคำนวณยอดเงินรวมอัตโนมัติ</td></tr><tr><td>FR-CART-02</td><td>รายการสินค้าที่ชอบ (Wishlist)</td><td>ลูกค้า</td><td>ลูกค้าสามารถกดบันทึกเกมที่สนใจเก็บไว้ในรายการส่วนตัวเพื่อกลับมาดูหรือสั่งซื้อในภายหลังได้</td></tr><tr><td>FR-PAY-01</td><td>ชำระเงินออนไลน์</td><td>ลูกค้า</td><td>ลูกค้าสามารถยืนยันคำสั่งซื้อและทำรายการชำระเงิน (จำลองการชำระเงิน/แนบสลิป)</td></tr><tr><td>FR-ORD-01</td><td>ตัดสต็อกอัตโนมัติ</td><td>ระบบ (System)</td><td>เมื่อลูกค้าชำระเงินสำเร็จ ระบบจะทำการตัดจำนวนสต็อกสินค้าในฐานข้อมูลทันที</td></tr><tr><td>FR-ORD-02</td><td>จัดการคำสั่งซื้อ</td><td>พนักงาน</td><td>พนักงานสามารถดูรายการสั่งซื้อที่เข้ามา ตรวจสอบการชำระเงิน และอัปเดตสถานะของออเดอร์ (เช่น รอจัดส่ง, จัดส่งแล้ว)</td></tr><tr><td>FR-API-01</td><td>จำลองสถานะจัดส่ง</td><td>ระบบ (System)</td><td>ระบบจะดึงข้อมูลจาก Mock Shipping API เพื่ออัปเดตสถานะพัสดุจำลองให้ลูกค้าสามารถติดตามได้ในหน้ารายละเอียดคำสั่งซื้อ</td></tr><tr><td>FR-DASH-01</td><td>รายงานยอดขาย</td><td>ผู้จัดการ</td><td>ระบบดึงข้อมูลคำสั่งซื้อที่สำเร็จแล้วมาแสดงผลในรูปแบบ Revenue Dashboard เพื่อให้ผู้จัดการดูสรุปยอดขายแบบภาพรวมได้</td></tr></tbody></table><h2 id="แผนภาพ" tabindex="-1">แผนภาพ <a class="header-anchor" href="#แผนภาพ" aria-label="Permalink to &quot;แผนภาพ&quot;">​</a></h2><h3 id="use-case-diagram" tabindex="-1">Use Case Diagram <a class="header-anchor" href="#use-case-diagram" aria-label="Permalink to &quot;Use Case Diagram&quot;">​</a></h3><h3 id="class-diagram" tabindex="-1">Class Diagram <a class="header-anchor" href="#class-diagram" aria-label="Permalink to &quot;Class Diagram&quot;">​</a></h3><h3 id="sequence-diagram" tabindex="-1">Sequence Diagram <a class="header-anchor" href="#sequence-diagram" aria-label="Permalink to &quot;Sequence Diagram&quot;">​</a></h3><h3 id="wireframe" tabindex="-1">Wireframe <a class="header-anchor" href="#wireframe" aria-label="Permalink to &quot;Wireframe&quot;">​</a></h3><h3 id="prototype" tabindex="-1">Prototype <a class="header-anchor" href="#prototype" aria-label="Permalink to &quot;Prototype&quot;">​</a></h3>',40)])])}const u=e(l,[["render",d]]);export{m as __pageData,u as default};
